  `AREA_NAME` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_vietnamese_ci DEFAULT NULL COMMENT 'TRIAL',
  `AREA_ZONE` varchar(255) DEFAULT NULL COMMENT 'Vùng khu vực (Mô tả địa giới hành chính)',
  `AREA_COORDINATES` varchar(500) DEFAULT NULL COMMENT 'Danh sách các điểm tọa độ trên bản đồ',
  `COLOR_CODE` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'Mã màu hiển thị cho khu vực',
  `DESCRIPTION` varchar(500) DEFAULT NULL COMMENT 'TRIAL',
