  `MODIFIED_BY` varchar(500) DEFAULT NULL COMMENT 'TRIAL',
  `modified_date` datetime DEFAULT NULL,
  `optimal_accumulation` double DEFAULT NULL,
  PRIMARY KEY (`AREA_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=1308628 DEFAULT CHARSET=utf8mb3 COMMENT='TRIAL';
