DROP TABLE IF EXISTS `v_camera`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `v_camera` (
  `CAM_ID` bigint NOT NULL AUTO_INCREMENT COMMENT 'TRIAL',
  `IS_ACTIVE` tinyint(1) DEFAULT '1' COMMENT 'TRIAL',
  `ROAD_ID` bigint NOT NULL,
  `AREA_ID` bigint DEFAULT NULL COMMENT 'TRIAL',
  `CAM_CODE` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'TRIAL',
  `CAM_NAME` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'TRIAL',
  `BRANCH` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'TRIAL',
  `ORIGIN` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'TRIAL',
  `DESCRIPTION` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'TRIAL',
  `CREATED_BY` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'TRIAL',
  `CREATED_DATE` datetime DEFAULT NULL,
  `MODIFIED_BY` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'TRIAL',
  `MODIFIED_DATE` datetime DEFAULT NULL,
  `STATUS` bigint DEFAULT '1' COMMENT 'TRIAL',
  `LOCATION` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'TRIAL',
  `URL_LIVE_STREAM` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'TRIAL',
  `URL_SFTP` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'TRIAL',
  `LOCATION_REAL_NAME` varchar(1000) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'TRIAL',
  `LOCATION_IMAGE` longtext CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci COMMENT 'TRIAL',
  `DIRECTION` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'hướng giám sát',
  `DIRECTION_NUMBER` int DEFAULT NULL,
  `DIRECTION_OF_SUPERVISION` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'hướng giám sát',
  `TYPE` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `EXTERNAL_ID` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'ID_CAMERA_VMS',
  `URL_TIMELINE` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `PHYSICAL_DIRECTION` varchar(5000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `URL_THUMBNAIL` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `CHANNEL_ID` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `FLOW_SECOND_LOCATION` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `URL_HLS` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'Lấy dữ liệu lưu lượng TrafficLight',
  `IP` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'PHI TẠO - k dung nua -> xoa',
  `device_type_id` bigint NOT NULL COMMENT 'loai camera',
  `vms_live_status` int DEFAULT '1' COMMENT 'connect status của cam',
  `data_account` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `data_password` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  PRIMARY KEY (`CAM_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=10000563 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='TRIAL';
