DROP TABLE IF EXISTS `v_cycle`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `v_cycle` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `is_active` int DEFAULT NULL,
  `cross_id` bigint DEFAULT NULL,
  `cycle_name` varchar(255) DEFAULT NULL,
  `parent_cycle_id` bigint DEFAULT NULL,
  `red_clear` int DEFAULT NULL,
  `yellow` int DEFAULT NULL,
  `number_of_stages` int DEFAULT NULL,
  `description` varchar(2000) DEFAULT NULL,
  `cycle_type` int NOT NULL COMMENT 'chu ky goc = 0, chu ky con = 1, chu ky lan song xanh = 2',
  `cycle_length` int DEFAULT NULL,
  `created_by` varchar(500) DEFAULT NULL,
  `created_date` datetime DEFAULT NULL,
  `modified_by` varchar(500) DEFAULT NULL,
  `modified_date` datetime DEFAULT NULL,
  `old_id` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=732 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

