  `route` int DEFAULT NULL,
  `old_id` varchar(50) DEFAULT NULL,
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `active_status` varchar(255) DEFAULT NULL,
  `road_id` bigint DEFAULT NULL,
  `live_status` tinyint NOT NULL DEFAULT '1',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1874 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
