--
-- Table structure for table `v_road`
--

DROP TABLE IF EXISTS `v_road`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `v_road` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `is_active` int NOT NULL DEFAULT '1',
  `road_name` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `from_cross` bigint DEFAULT NULL,
  `from_cross_direction` int DEFAULT NULL,
  `to_cross` bigint DEFAULT NULL,
  `to_cross_direction` int DEFAULT NULL,
  `number_of_lanes` int NOT NULL,
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `created_date` datetime DEFAULT NULL,
  `created_by` varchar(500) DEFAULT NULL,
  `modified_date` datetime DEFAULT NULL,
  `modified_by` varchar(500) DEFAULT NULL,
  `width` float DEFAULT NULL,
  `length` float DEFAULT NULL,
  `straight_proportion` float DEFAULT NULL COMMENT 'Tỉ lệ xe cộ rẽ phải của đường',
  `left_proportion` float DEFAULT NULL COMMENT 'Tỉ lệ xe cộ rẽ trái của đường',
  `right_proportion` float DEFAULT NULL COMMENT 'Tỉ lệ xe cộ rẽ phải của đường',
  `capacity_design` int DEFAULT NULL COMMENT 'Thiết kế lưu lượng tối đa của đường',
  `road_type` int DEFAULT NULL COMMENT '"Loại đường theo TCVN: +....',
  `speed_design` int DEFAULT NULL COMMENT 'Thiết kế tốc độ cho phép của đường',
  `capacity_utilization` double DEFAULT NULL COMMENT 'Hệ số sử dụng KNTH (capacity_design)',
  `weight` float DEFAULT NULL COMMENT 'Trọng số của đường',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1312 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

